from collections import deque
class Queue:
    def __init__(self):
        self.queue = deque()
    def front(self):
        return self.queue[0]
    def fixQueue(self):
        return self.queue.popleft()

q = Queue()
for num in [2, 3, 4]:
    q.queue.append(num)
print(q.fixQueue())
print(q.front())

solutions.cpp:
#include <iostream>
#include <vector>
#include <deque>

using namespace std;

class Queue {
public:
    vector<int> queue;
    int front() {
        return queue[0];
    }
    void fixQueue() {
        return queue.erase(queue.begin());
    }
};

int main() {
    Queue q;
    for (int k = 2; k <= 4; ++k) {
        q.queue.push_back(k);
    }
    q.fixQueue();
    cout << q.front();
    cout << endl;
    return 0;
}
